#include <bits/stdc++.h>
using namespace std;
int main(){
    int n,m,a[1003][1003],s1=0,s2=0;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)cin>>a[i][j];
    for(int i=1;i<=n;i++)s1+=a[m][i];
    for(int i=1;i<=n;i++)s2+=a[i][m];
    cout<<s1<<' '<<s2<<' '<<s1+s2;
    return 0;
}
